-- 插入问题数据
INSERT INTO `question` (`question_title`, `question_content`, `user_id`, `view_count`, `reply_count`, `is_resolved`, `publish_time`, `del_flag`, `create_by`, `create_time`, `update_by`, `update_time`) VALUES
('总是失眠怎么办？', '最近一个月总是失眠，躺床上两三个小时都睡不着，白天又很困，情绪也变得很差，请问有什么办法可以改善睡眠？', 1001, 356, 5, 1, '2026-01-10 20:30:00', '0', '1001', '2026-01-10 20:30:00', '', NULL),
('如何克服社交恐惧？', '每次参加聚会或者和陌生人说话都会心跳加速、手心冒汗，特别紧张，这严重影响了我的工作和生活，想请教如何克服社交恐惧？', 1003, 289, 4, 1, '2026-01-12 15:20:00', '0', '1003', '2026-01-12 15:20:00', '', NULL),
('孩子厌学怎么办？', '孩子今年14岁，最近两个月经常找各种理由不去上学，成绩下滑严重，跟他沟通也不愿意说，作为家长很着急，该怎么办？', 1005, 421, 6, 1, '2026-01-15 09:00:00', '0', '1005', '2026-01-15 09:00:00', '', NULL),
('分手后走不出来怎么办？', '和交往3年的恋人分手已经2个月了，但还是每天都会想起ta，做什么都提不起兴趣，对未来感到迷茫，怎样才能快点走出来？', 1007, 198, 3, 0, '2026-01-18 22:15:00', '0', '1007', '2026-01-18 22:15:00', '', NULL),
('职场压力大到崩溃怎么办？', '最近工作压力特别大，每天都加班到很晚，领导要求很高，感觉自己快撑不住了，经常想哭，该怎么调节？', 1009, 267, 4, 1, '2026-01-20 18:30:00', '0', '1009', '2026-01-20 18:30:00', '', NULL),
('如何判断自己是否需要心理咨询？', '最近情绪一直不太好，但又不知道是不是到了需要心理咨询的程度，想问问什么情况下应该寻求专业帮助？', 1002, 178, 3, 0, '2026-01-22 14:00:00', '0', '1002', '2026-01-22 14:00:00', '', NULL),
('总觉得自己不够好怎么办？', '无论做什么都觉得自己做得不够好，总担心别人对自己有负面评价，这种想法让我很痛苦，怎么才能建立自信？', 1004, 234, 4, 1, '2026-01-25 11:30:00', '0', '1004', '2026-01-25 11:30:00', '', NULL),
('如何与青春期的孩子沟通？', '孩子进入青春期后不愿意跟我们说话，回家就把自己关在房间里，我们想关心ta却总是被抗拒，怎么改善亲子沟通？', 1006, 156, 2, 0, '2026-01-27 20:00:00', '0', '1006', '2026-01-27 20:00:00', '', NULL);

-- 插入回复数据（包含咨询师回复和普通用户回复）
INSERT INTO `question_reply` (`reply_content`, `reply_time`, `user_id`, `consult_id`, `question_id`, `is_best`, `del_flag`, `create_by`, `create_time`, `update_by`, `update_time`) VALUES
-- 问题1的回复
('建议你建立规律的作息时间，每天固定时间上床和起床。睡前1小时远离电子设备，可以尝试听轻音乐或做深呼吸放松。如果持续严重，建议来心理科就诊。', '2026-01-11 09:30:00', NULL, 2, 1, 1, '0', '2', '2026-01-11 09:30:00', '', NULL),
('我也是失眠患者，试过泡脚和冥想，有一定效果，你可以试试看。', '2026-01-11 14:20:00', 1010, NULL, 1, 0, '0', '1010', '2026-01-11 14:20:00', '', NULL),
('失眠和情绪有关，建议白天适度运动，不要补觉，逐渐调整生物钟。', '2026-01-12 08:15:00', NULL, 6, 1, 0, '0', '6', '2026-01-12 08:15:00', '', NULL),
-- 问题2的回复
('社交恐惧可以通过系统脱敏逐步改善。建议从低社交压力的场景开始，如先在线上社群交流，再逐步过渡到线下小范围聚会。必要时可以结合认知行为疗法。', '2026-01-13 10:00:00', NULL, 1, 2, 1, '0', '1', '2026-01-13 10:00:00', '', NULL),
('我也有过类似经历，后来参加了一个社交训练小组，慢慢改善了，建议你可以试试。', '2026-01-13 16:30:00', 1012, NULL, 2, 0, '0', '1012', '2026-01-13 16:30:00', '', NULL),
-- 问题3的回复
('青春期孩子厌学常见，建议你先不要指责，试着了解孩子在学校是否有压力或者人际问题。可以和孩子约定每周一次"不带评判"的交流时间，多倾听少说教。', '2026-01-16 10:30:00', NULL, 5, 3, 0, '0', '5', '2026-01-16 10:30:00', '', NULL),
('建议带孩子做一次心理咨询，先了解厌学的深层原因。同时家长要调整对成绩的期待，多关注孩子的情绪状态。', '2026-01-16 15:00:00', NULL, 9, 3, 1, '0', '9', '2026-01-16 15:00:00', '', NULL),
('我孩子之前也厌学，后来我发现是因为被同学欺负了，解决之后就好了。建议你先了解孩子在学校的情况。', '2026-01-17 09:00:00', 1015, NULL, 3, 0, '0', '1015', '2026-01-17 09:00:00', '', NULL),
-- 问题4的回复
('分手后的悲伤是正常的，给自己一些时间去哀悼这段关系。建议你把注意力转移到自己身上，培养新的兴趣爱好，重建自己的生活重心。如果持续走不出来，可以寻求心理咨询支持。', '2026-01-19 14:30:00', NULL, 7, 4, 0, '0', '7', '2026-01-19 14:30:00', '', NULL),
('时间是最好的良药，三个月前我也经历过分手，现在好多了。建议你多和朋友在一起，不要一个人待着。', '2026-01-20 10:00:00', 1013, NULL, 4, 0, '0', '1013', '2026-01-20 10:00:00', '', NULL),
-- 问题5的回复
('职场压力需要从认知和行为两个层面调节。建议你先评估压力源，区分哪些可控哪些不可控。下班后要有明确的工作和生活界限，保留自己的充电时间。必要时可以申请调休或休假。', '2026-01-21 09:00:00', NULL, 10, 5, 1, '0', '10', '2026-01-21 09:00:00', '', NULL),
('我也经历过高压期，建议你学习一些时间管理技巧，提高工作效率。同时不要对自己要求太完美，允许自己有"够好"就可以了。', '2026-01-21 16:30:00', 1014, NULL, 5, 0, '0', '1014', '2026-01-21 16:30:00', '', NULL),
-- 问题6的回复
('一般建议当情绪困扰持续两周以上，并影响了日常功能（如工作、学习、社交）时，就应该考虑寻求专业帮助。另外如果有自我伤害的想法，一定要立即求助。', '2026-01-23 11:00:00', NULL, 4, 6, 0, '0', '4', '2026-01-23 11:00:00', '', NULL),
-- 问题7的回复
('这种不配得感往往来自童年的经历或内在批评的声音。建议你练习自我关怀，每天写下3件做得好或值得肯定的事情。也可以尝试"不完美挑战"，允许自己犯错，逐步降低对自己的要求。', '2026-01-26 09:30:00', NULL, 3, 7, 1, '0', '3', '2026-01-26 09:30:00', '', NULL),
('我也是个对自己要求很高的人，后来学了一个方法：想象如果是最好的朋友遇到同样的情况，你会怎么安慰ta？然后用同样的方式对待自己。', '2026-01-26 14:00:00', 1011, NULL, 7, 0, '0', '1011', '2026-01-26 14:00:00', '', NULL),
-- 问题8的回复
('青春期的孩子需要被尊重和被倾听。建议你调整沟通方式，少用"你应该"，多用"我感受到"。可以创造一些非正式沟通的机会，比如一起散步、开车时聊天，减少面对面的压迫感。', '2026-01-28 10:00:00', NULL, 5, 8, 0, '0', '5', '2026-01-28 10:00:00', '', NULL);

